using Xunit.Sdk;namespace Smoower.Minified.Tests;public class AssertExtensionsTests{[F] public void Eq_PassesAndReturnsActual() => Assert.Equal(2, 2.eq(2));[F] public void Eq_FailsOnMismatch() => Assert.Throws<EqualException>(() => 2.eq(3));[F] public void Neq_Passes() => 2.neq(3);[F] public void Tru_And_Fls() { true.tru(); false.fls(); }[F] public void Nul_And_NotNul() { object? n = null; n.nul(); Assert.Equal("x", "x".notNul()); }[F] public void IsType_ReturnsTyped() => Assert.Equal(5, ((object)5).isType<int>());[F] public void IsAssignable_ReturnsTyped() => Assert.Equal("s", ((object)"s").isAssignable<string>());[F] public void Same_Passes() { var o = new object(); o.same(o); }[F] public void Empty_And_NotEmpty() { Array.Empty<int>().empty(); new[] { 1 }.notEmpty(); }[F] public void Len_Counts() => new[] { 1, 2, 3 }.len(3);[F] public void Contains_Finds() => new[] { 1, 2, 3 }.contains(2);[F] public void Has_FindsByPredicate() => new[] { 1, 2, 3 }.has(x => x == 2);[F] public void HasText_FindsSubstring() => "hello world".hasText("o w");[F] public void EqSeq_ComparesElements() => new List<int> { 1, 2 }.eqSeq(new[] { 1, 2 });[F] public void Sole_ReturnsSingle() => Assert.Equal(7, new[] { 7 }.sole());[F] public void NotSame_Passes() => new object().notSame(new object());[F] public void InRange_Passes() => 5.inRange(1, 10);[F] public void Throws_Captures()=> ((Action)(() => throw new InvalidOperationException())).throws<InvalidOperationException>();[F] public async Task ThrowsAsync_Captures()=> await ((Func<Task>)(async () => { await Task.Yield(); throw new InvalidOperationException(); })).throwsAsync<InvalidOperationException>();}
